package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    public void testGetRecordSeparator() throws NoSuchFieldException, IllegalAccessException {
        // Create an instance of CSVFormat
        CSVFormat csvFormat = createCSVFormat();

        // Use reflection to set the private field 'recordSeparator' to test value
        try {
            Field field = CSVFormat.class.getDeclaredField("recordSeparator");
            field.setAccessible(true);
            field.set(csvFormat, "TestRecordSeparator");
        } catch (NoSuchFieldException | IllegalAccessException e) {
            e.printStackTrace();
        }

        // Call the getRecordSeparator method
        String recordSeparator = csvFormat.getRecordSeparator();

        // Verify the result
        assertEquals("TestRecordSeparator", recordSeparator);
    }

    private CSVFormat createCSVFormat() {
        return CSVFormat.DEFAULT;
    }
}
